_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = .5+(vUv-0.5)*uAspect.xy;
float dist = sqrt(pow(q1-uv1.x,2)+pow(q2-uv1.y,2));
float ang1 = -atan(q2-uv1.y,q1-uv1.x);

if (q4==0) {
if (dist + .05*tan(.5*ang1+.5*q7)*q8 <.2) { vUv+=.01*tan(.5*ang1+.5*q7) ; } ;
};

if (q4==1) {
if (sin(int(20*uv1.x)) > 0) { vUv.y+=.5*(-q1+.5) ; } else {vUv.y-=.5*(-q1+.5);};
if (sin(int(20*uv1.y)) > 0) { vUv.x+=.5*(-q2+.5) ; } else {vUv.x-=.5*(-q2+.5);};
};

if (q4==2) {
float s1=int(80/sin(7*dist+q7));        float s2=s1*s1;
float i=s1*int(s1*vUv.x)+int(s1*vUv.y);
vUv.x=(i%s2)/s2;
vUv.y=(i%s1)/s1;
} ;

if (q4==3) {
float s1=10*(1+.5*q8)/dist;        float s2=s1*s1;
float i=s1*int(s1*vUv.x)+int(s1*vUv.y);
if (dist + .05*tan(.5*ang1+.5*q7)*q8 <.2) { vUv.x=(i%s2)/s2; vUv.y=(i%s1)/s1; } ;
} ;

if (q4==4) {
vUv.x += sign(sin((200*vUv.x))) * q1;
} ;

if (q4==5) {
if (dist<.2+.05*sin(1*ang1+q7)*cos(6*ang1+q7))
{ vUv.x -=.02*sin(1*ang1+q7)*cos(6*ang1+q7); } ;
}  ;

if (q4==6) {
if (dist>.1) { vUv.y -= .3*(vUv-.5)*sin(35*dist-q7); } ;
} ;

if (q4==7) {
if (dist>.15) { vUv += sin(7*ang1+q7)*5*q8*(vUv-.5)*dist*dist; } ;
} ;

if (q4==8) {
vUv.x+=-.5+q1;    vUv.y +=-.5+ q2;  vUv = uAspect.xy*(vUv-.5);
vUv = .2*normalize(vUv)*tan(6*length(1*vUv)) - vec2(.05*q7,.06*q7);
} ;

if (q4==9) {
if (dist<.2+.05*sin(1*ang1+q7)*cos(6*ang1+q7))
{vUv -= tan(10*q8+.5*ang1+q7)*.005*q8*(vUv-.5)/(dist*dist);}
} ;

if (q4==10) {
if (dist+.01*q8*sin(6*ang1+5*q7)>.1) { vUv -= q8*(vUv-.5)/dist + vec2(.1*q7,-.13*q7); } ;
} ;

if (q10) { ret=(texture(sampler_rand00,vUv)); }
if (q11) { ret=(texture(sampler_rand01,vUv)); }
if (q12) { ret=(texture(sampler_rand02,vUv)); }



  fragColor = ret;
}
